from src.nodes.base import BaseNode

class PrismGetEntityInfoNode(BaseNode):
    name = "Prism: Get Entity Info"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("entity", "dict")
        self.add_output("type", "string")
        self.add_output("name", "string")
        self.add_output("sequence", "string")
        self.add_output("shot_name", "string")
        self.add_output("asset_path", "string")
        self.add_output("path", "string")
        self.add_output("display_name", "string")

    async def execute(self, inputs):
        entity = inputs.get('entity') or {}
        etype = str(entity.get('type', '')).lower()
        fs_path = str(entity.get('path', ''))
        if etype == 'shot':
            seq = str(entity.get('sequence', ''))
            shot = str(entity.get('shot', entity.get('name', '')))
            display = f'{seq}/{shot}' if seq else shot
            return {'type': 'shot', 'name': shot, 'sequence': seq,
                    'shot_name': shot, 'asset_path': '', 'path': fs_path, 'display_name': display}
        elif etype == 'asset':
            apath = str(entity.get('asset_path', entity.get('name', '')))
            leaf = apath.split('/')[-1] if apath else ''
            return {'type': 'asset', 'name': leaf, 'sequence': '',
                    'shot_name': '', 'asset_path': apath, 'path': fs_path, 'display_name': apath}
        else:
            return {'type': etype, 'name': str(entity.get('name', '')),
                    'sequence': '', 'shot_name': '', 'asset_path': '', 'path': fs_path,
                    'display_name': str(entity.get('name', etype))}

def register_node():
    return PrismGetEntityInfoNode
